project.core.extract_weights.code:
@lru_cache(maxsize=1024)
def extract_weights(m: int, k: int) -> Weights:
    cp = tuple((r for r in range(1, m) if gcd(r, m) == 1))
    phi_m = len(cp)
    h2 = (phi_m > 0 and all((r % 2 == 1 for r in cp))) and k % 2 == 1 and (m % 2 == 0)
    r_count = 0
    canon = None
    if not h2:
        if k == 3:
            cp_set = set(cp)
            for r0 in cp:
                for r1 in cp:
                    r2 = (m - r0 - r1) % m
                    if r2 == 0:
                        r2 = m
                    if r2 in cp_set:
                        if _check_fso_solvability(m, (r0, r1, r2)):
                            r_count += 1
                            if canon is None:
                                canon = (r0, r1, r2)
        else:
            mid = m - (k - 1)
            if mid > 0 and gcd(mid, m) == 1:
                canon = (1,) * (k - 1) + (mid,)
                r_count = 1
    full_exp = (m ** 3 if m > 0 else 1) * log2(6)
    search_exp = m * log2(_LEVEL_COUNTS.get(m, phi_m * 6)) if m > 0 else 0
    return Weights(m, k, h2, r_count, canon, phi_m, search_exp, search_exp / full_exp if full_exp > 0 else 1.0, phi_m, m ** max(1, m - 1), cp)

project.core.verify_sigma.code:
def verify_sigma(sigma: Dict[Tuple, Tuple], m: int) -> bool:
    if not sigma or len(sigma) != m ** 3:
        return False
    n = m ** 3
    for c in range(3):
        vis = set()
        cur = (0, 0, 0)
        for _ in range(n):
            if cur in vis:
                return False
            vis.add(cur)
            p = sigma.get(cur)
            if not p:
                return False
            arc = p[c]
            nxt = list(cur)
            nxt[arc] = (nxt[arc] + 1) % m
            cur = tuple(nxt)
        if len(vis) != n or cur != (0, 0, 0):
            return False
    return True

