project.core._sa_score.code:
def _sa_score(sigma, arc_s, pa, n, k):
    score = 0
    for c in range(k):
        vis = bytearray(n)
        comps = 0
        for s in range(n):
            if not vis[s]:
                comps += 1
                cur = s
                while not vis[cur]:
                    vis[cur] = 1
                    cur = arc_s[cur][pa[sigma[cur]][c]]
        score += comps - 1
    return score

project.core._build_sa.code:
def _build_sa(m, k):
    n = m ** k
    all_p = [list(p) for p in permutations(range(k))]
    nP = len(all_p)
    arc_s = [[0] * k for _ in range(n)]
    pa = [[None] * k for _ in range(nP)]
    for idx in range(n):
        coords = []
        val = idx
        for _ in range(k):
            coords.append(val % m)
            val //= m
        coords.reverse()
        for c in range(k):
            nxt = list(coords)
            nxt[c] = (nxt[c] + 1) % m
            ni = 0
            for v in nxt:
                ni = ni * m + v
            arc_s[idx][c] = ni
    for pi, p in enumerate(all_p):
        for at, c in enumerate(p):
            pa[pi][c] = at
    return (n, arc_s, pa, all_p)

project.core.run_hybrid_sa.code:
def run_hybrid_sa(m, k=3, seed=0, max_iter=1000):
    n, arc_s, pa, all_p = _build_sa(m, k)
    nP = len(all_p)
    rng = random.Random(seed)
    sigma = [rng.randrange(nP) for _ in range(n)]
    cs = _sa_score(sigma, arc_s, pa, n, k)
    bs = cs
    best = sigma[:]
    for _ in range(max_iter):
        if cs == 0:
            break
        v = rng.randrange(n)
        old = sigma[v]
        sigma[v] = rng.randrange(nP)
        ns = _sa_score(sigma, arc_s, pa, n, k)
        if ns <= cs:
            cs = ns
            if cs < bs:
                bs = cs
                best = sigma[:]
        else:
            sigma[v] = old
    best_sol_dict = {}
    for idx, pi in enumerate(best):
        coords = []
        val = idx
        for _ in range(k):
            coords.append(val % m)
            val //= m
        coords.reverse()
        best_sol_dict[tuple(coords)] = tuple(all_p[pi])
    sol = best_sol_dict if bs == 0 else None
    return (sol, {'best': bs, 'best_sigma': best_sol_dict})

