def is_single_q_cycle(Q: QFunc, m: int) -> bool:
    """Check that permutation Q on Z_m² is a single m²-cycle."""
    n = m * m
    visited: set = set()
    cur: FiberPos = (0, 0)
    while cur not in visited:
        visited.add(cur)
        cur = Q[cur]
    return len(visited) == n and cur == (0, 0)

