def run_verbose(self, max_iter: int=500000) -> Optional[SigmaFn]:
    print(f'SimulatedAnnealing m={self.m}  max_iter={max_iter:,}  T={self.T_init}→{self.T_min}')
    result = self.run(max_iter=max_iter, verbose=True, report_every=50000)
    if result:
        print(f'  ✅ Found!  elapsed={self._elapsed:.1f}s')
    else:
        print(f'  ❌ Best score={self._best_score}  elapsed={self._elapsed:.1f}s')
    return result

project.search._score.code:
def _score(self, funcs: List[FuncGraph], m: int) -> int:
    """Sum of extra components (0 = perfect)."""
    total = 0
    for fg in funcs:
        visited: set = set()
        comps = 0
        for start in fg:
            if start not in visited:
                comps += 1
                cur = start
                while cur not in visited:
                    visited.add(cur)
                    cur = fg[cur]
        total += comps - 1
    return total

project.search._bt.code:
def _bt(idx: int) -> bool:
    if idx == n:
        for fg in funcs:
            ok, _ = verify_functional_graph(fg, m)
            if not ok:
                return False
        return True
    v = verts[idx]
    neighbors = [tuple(((v[d] + ARC_SHIFTS[at][d]) % m for d in range(3))) for at in range(3)]
    perms = _ALL_PERMS[:]
    self.rng.shuffle(perms)
    for perm in perms:
        self._nodes += 1
        conflict = any((in_deg[perm[at]].get(neighbors[at], 0) >= 1 for at in range(3)))
        if conflict:
            continue
        sigma[v] = perm
        for at, c in enumerate(perm):
            funcs[c][v] = neighbors[at]
            in_deg[c][neighbors[at]] = in_deg[c].get(neighbors[at], 0) + 1
        if _bt(idx + 1):
            self._elapsed = time.perf_counter() - t0
            return True
        del sigma[v]
        for at, c in enumerate(perm):
            del funcs[c][v]
            in_deg[c][neighbors[at]] -= 1
            if in_deg[c][neighbors[at]] == 0:
                del in_deg[c][neighbors[at]]
    return False

